import{c as t,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse(`{"title":"Ben's Bites — 2026-04-30","description":"","frontmatter":{"title":"Ben's Bites — 2026-04-30","date":"2026-04-30T00:00:00.000Z","source":"Ben's Bites","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-30-bens-bites.md","filePath":"research/ai-news/2026-04/2026-04-30-bens-bites.md","lastUpdated":1779796674000}`),s={name:"research/ai-news/2026-04/2026-04-30-bens-bites.md"};function o(i,e,l,p,h,m){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="🍔-ben-s-bites-—-2026-04-30" tabindex="-1">🍔 Ben&#39;s Bites — 2026-04-30 <a class="header-anchor" href="#🍔-ben-s-bites-—-2026-04-30" aria-label="Permalink to &quot;🍔 Ben&#39;s Bites — 2026-04-30&quot;">​</a></h1><blockquote><p>Ben Tossell 的 AI 日報，工具圈消息源 來源：<a href="https://www.bensbites.com/feed" target="_blank" rel="noreferrer">Ben&#39;s Bites</a></p></blockquote><hr><h2 id="building-gets-easier" tabindex="-1"><a href="https://www.bensbites.com/p/building-gets-easier" target="_blank" rel="noreferrer">Building gets easier</a> <a class="header-anchor" href="#building-gets-easier" aria-label="Permalink to &quot;[Building gets easier](https://www.bensbites.com/p/building-gets-easier)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-04-30</em></p><p>Hey folks, today I want to quickly pay tribute to my dad, Matthew Tossell, who retires* today after 43 (!!!) years at his firm. That’s 40 years longer than I’ve ever worked anywhere - and Ben’s Bites is the only thing I’ve done for longer than 2 years 😯.</p><p>I learned a lot about hard work from him. Too much to put here - he transformed his law firm several times over 4 decades and most recently forced the company to adopt AI (I may have played a part here 😉).</p><p>I’ve saved the soppy shit for a letter I wrote him today - as he wrote me one when I sold my first company.</p><p>Happy retirement day, dad. I know you’re reading this - my biggest fan (the feelings mutual)</p><p>*retirement for him = started a new company, on the board of a university, school and Cardiff business council (plus whatever work I start giving him 😈)</p><p>Ok, AI stuff…</p><p>I’m becoming Codex-pilled… I’ve been using a terminal every day since realising it’s not scary any more, as it’s just talking to AI, but I forced myself to try the Codex app for tasks and I actually am starting to really really like it.</p><p>I still prefer being able to easily have multiple tabs next to one another but I like the Chat | Files (or browser) view a lot - something I never had with a terminal.</p><p>I built a dinosaur jumping game for Max and Arabella this morning. Set up a Gmail learning system to understand how to label + archive my emails (plus an automation for it). I’ve revamped my memory system and have been pilling in tons of bookmarks/youtube transcripts etc that I can reference any time.</p><p>I have a main folder ‘bites’ which has my general instructions for day-to day stuff:</p><p>So it speaks to me in a certain way, knows my memories, how I want it to behave etc. I have a running ‘todos’ thread that I work through each day - with a corresponding ‘TODOS.md’ file.</p><p>I desperately am waiting for a mobile version…</p><p>Working with agents is just files and access. I’m excited to keep trying this out for day-to-day and coding. But for ‘proper’ coding work I still use <a href="https://factory.ai" target="_blank" rel="noreferrer">droid</a> in the terminal.</p><p>Ben’s Bites is brought to you by <a href="https://ai4.io/register/?utm_source=paid_partner&amp;utm_campaign=bens_bites&amp;utm_term=newsletter" target="_blank" rel="noreferrer">Ai4 2026</a></p><p>Don’t miss <a href="https://ai4.io/register/?utm_source=paid_partner&amp;utm_campaign=bens_bites&amp;utm_term=newsletter" target="_blank" rel="noreferrer">Ai4 2026</a> — America’s largest AI conference! Join 12,000+ attendees, 1,000+ speakers, &amp; 400+ exhibits in Las Vegas, August 4-6. Get case studies from Fortune 500 execs on AI Agents, Generative AI &amp; more. Keynotes from Geoffrey Hinton, Fei-Fei Li, and Andrew Ng. <a href="https://ai4.io/register/?utm_source=paid_partner&amp;utm_campaign=bens_bites&amp;utm_term=newsletter" target="_blank" rel="noreferrer">Learn more &amp; register now!</a></p><p>Headlines</p><p><a href="https://blog.cloudflare.com/agents-stripe-projects/" target="_blank" rel="noreferrer">Cloudflare now lets agents create accounts, buy domains and deploy</a>. An agent can provision a Cloudflare account, start a paid subscription, register a domain, get an API token and deploy without you doing dashboard/admin gymnastics. Humans still approve terms and permissions, but the setup maze is getting agent-readable. Lots of companies are moving this way, letting less-technical people like us just get stuff built without worrying about all the services in the middle.</p><p><a href="https://stripe.com/blog/everything-we-announced-at-sessions-2026" target="_blank" rel="noreferrer">Stripe announced 288 things at Sessions</a>, relevant ones: Agentic Commerce Suite, <a href="https://stripe.com/blog/giving-agents-the-ability-to-pay" target="_blank" rel="noreferrer">Link&#39;s wallet for agents</a>, streaming payments and agent-ready Treasury accounts. There is also a <a href="https://github.com/stripe/link-cli" target="_blank" rel="noreferrer">Link CLI</a> that gives agents one-time-use payment credentials from your Link wallet, without exposing your real card details.</p><p><a href="https://cursor.com/blog/typescript-sdk" target="_blank" rel="noreferrer">Cursor SDK</a> - build agents using the same runtime, harness and models that power Cursor.</p><p><a href="https://www.warp.dev/blog/warp-is-now-open-source" target="_blank" rel="noreferrer">Warp is now open-source</a> and OpenAI is the founding sponsor for the repo. Warp&#39;s bet is that contributors bring taste/direction/verification while agents do more of the implementation work.</p><p><a href="https://lightfield.app/blog/meet-skills?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=bens_bites&amp;utm_content=secondary_4-30-2026" target="_blank" rel="noreferrer">Lightfield</a> is an AI-native CRM that just shipped Skills. Define any workflow in plain English and trigger it with a sentence. The AI agent executes against your full data graph with code execution, web search, and file I/O. <a href="https://lightfield.app/blog/meet-skills?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=bens_bites&amp;utm_content=secondary_4-30-2026" target="_blank" rel="noreferrer">Try Lightfield</a> (use code BENSBITESS23 for 3 months free)*</p><p>My feed</p><p><a href="https://x.com/dkundel/status/2049591675518165134" target="_blank" rel="noreferrer">The most fun I’ve had building apps</a>: GPT-5.5 + GPT-Image-2</p><p><a href="https://www.youtube.com/watch?v=MhHEGMFCEB0" target="_blank" rel="noreferrer">Codex masterclass workshop</a> from AI Engineer London, plus <a href="https://developers.openai.com/api/docs/guides/prompt-guidance?model=gpt-5.5" target="_blank" rel="noreferrer">GPT-5.5 prompt guidance</a></p><p><a href="https://www.youtube.com/watch?v=n5f51gtuGHE" target="_blank" rel="noreferrer">Building Pi,</a> and what makes self-modifying software so fascinating</p><p><a href="https://www.youtube.com/watch?v=hNDyKQXjVbU" target="_blank" rel="noreferrer">Fred Wilson on 40 years in venture</a> — and why USV is automating itself</p><p><a href="https://martinfowler.com/fragments/2026-04-29.html" target="_blank" rel="noreferrer">Martin Fowler’s updated AI coding notes</a> - verification, guardrails and the difference between vibe coding and agentic engineering.</p><p><a href="https://x.com/OpenRouter/status/2049145538373947541" target="_blank" rel="noreferrer">Poolside’s first public models</a>, Laguna M.1 and Laguna XS.2, are now on OpenRouter. Built for agentic coding and long-horizon work.</p><p><a href="https://here.now/" target="_blank" rel="noreferrer">here.now</a> now has private cloud storage for agents as well as instant web publishing. I synced all my local memory and files (2.5k files to this with one prompt - tweet is below)</p><p><a href="https://x.com/ctatedev/status/2049350311106511178" target="_blank" rel="noreferrer">Stripe emulator skill</a> - offline, stateful Stripe emulation for checkout pages, webhooks and deterministic CI without secrets.</p><p><a href="https://x.com/mattpocockuk/status/2049506712801935611" target="_blank" rel="noreferrer">Sandcastle</a> - Matt Pocock open-sourced his software factory.</p><p><a href="https://x.com/ajassy/status/2049191826251538833" target="_blank" rel="noreferrer">Quick</a> by Amazon connects to email, calendar, Slack and local files to flag important stuff, summarize information and automate tasks.</p><p><a href="https://martinfowler.com/fragments/2026-04-29.html?utm_source=bensbites" target="_blank" rel="noreferrer">Some good posts</a> on AI coding for senior engineers, harness engineering, why people hate AI, and yet, the race to adopt it.</p><p><a href="https://osscar.dev/" target="_blank" rel="noreferrer">OSSCAR</a> - a quarterly index of the fastest-growing open-source orgs from Supabase and &gt;commit.</p><p><a href="https://lucumr.pocoo.org/2026/4/28/before-github/" target="_blank" rel="noreferrer">Before GitHub</a> - Armin Ronacher on how open-source collaboration worked before GitHub.</p><p><a href="https://x.com/ElevenLabs/status/2049493164902187301" target="_blank" rel="noreferrer">ElevenMusic</a> - discover, remix, create and earn from music built on ElevenLabs’ music model.</p><p><a href="https://openai.com/index/where-the-goblins-came-from/" target="_blank" rel="noreferrer">OpenAI explained the goblins</a>. OpenAI models have been increasingly mentioning creators in chats. They found out why, but GPT-5.5 was trained before the fix.</p><p><a href="https://x.com/stephzhan/status/2049518659513852109https://www.youtube.com/watch?v=96jN2OCOfLs&amp;list=PLOhHNjZItNnOkkZThzULo1Ygg7JR6T3MG&amp;index=1" target="_blank" rel="noreferrer">Andrej Karpathy at Sequoia AI Ascent</a> on vibe coding vs agentic engineering. And also linking <a href="https://youtu.be/AFpeWo1GTeg?list=PLOhHNjZItNnOkkZThzULo1Ygg7JR6T3MG" target="_blank" rel="noreferrer">Demis’ talk from the event too</a>.</p><p><a href="https://mitchellh.com/writing/ghostty-leaving-github" target="_blank" rel="noreferrer">Ghostty is leaving GitHub</a>, with Mitchell Hashimoto writing up why.</p><p>Afters</p><p>poppy ‘watching’ the fred wilson video with me 😊</p><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben’s Bites</p><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p><ul><li>sponsors who make this newsletter possible 😃</li></ul><p>Wanna partner with us for the next quarter?</p><p>Email us at <a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></p><hr>',53)])])}const c=t(s,[["render",o]]);export{u as __pageData,c as default};
